from dataclasses import dataclass
from math import hypot

@dataclass(frozen=True)
class Point:
    """Represents an immutable 2D point with double precision coordinates."""

    x: float
    y: float

    def distance_to(self, other: 'Point') -> float:
        """Return the Euclidean distance between this point and another."""
        if not isinstance(other, Point):
            raise TypeError('distance_to expects a Point instance')
        return hypot(self.x - other.x, self.y - other.y)


def midpoint(a: Point, b: Point) -> Point:
    """Return the midpoint between points `a` and `b`."""
    if not isinstance(a, Point) or not isinstance(b, Point):
        raise TypeError('midpoint expects Point instances')
    return Point((a.x + b.x) / 2, (a.y + b.y) / 2)

